using System;`nusing System.Collections.Generic;`nusing GestaoManutencao.Core.Enums;`nusing GestaoManutencao.Core.Interfaces;`nusing GestaoManutencao.Core.Domain.Equipamentos;`nusing GestaoManutencao.Core.Exceptions;`n`nnamespace GestaoManutencao.Core.Domain`n{`n    public class SolicitacaoManutencao`n    {`n        public Guid Id { get; private set; }`n        public string Descricao { get; private set; }`n        public DateTime DataAbertura { get; private set; }`n        public NivelUrgencia Urgencia { get; private set; }`n        public Cliente Cliente { get; private set; }`n        public Equipamento Equipamento { get; private set; }`n        public Tecnico TecnicoResponsavel { get; private set; }`n        public ISolicitacaoState EstadoAtual { get; private set; }`n        public Prioridade Prioridade { get; private set; }`n`n        private readonly List<ServicoRealizado> _servicos = new List<ServicoRealizado>();`n        public IReadOnlyCollection<ServicoRealizado> Servicos => _servicos.AsReadOnly();`n`n        public SolicitacaoManutencao(string descricao, NivelUrgencia urgencia, Cliente cliente, Equipamento equipamento, IEstrategiaPriorizacao estrategiaPriorizacao)`n        {`n            if (string.IsNullOrWhiteSpace(descricao))`n                throw new SolicitacaoInvalidaException("Descricao da solicitacao eh obrigatoria.");`n            if (cliente == null)`n                throw new SolicitacaoInvalidaException("Cliente eh obrigatorio.");`n            if (equipamento == null)`n                throw new SolicitacaoInvalidaException("Equipamento eh obrigatorio.");`n            if (equipamento.Proprietario.Id != cliente.Id)`n                throw new SolicitacaoInvalidaException("O equipamento deve pertencer ao cliente da solicitacao.");`n            if (estrategiaPriorizacao == null)`n                throw new ArgumentNullException(nameof(estrategiaPriorizacao));`n`n            Id = Guid.NewGuid();`n            Descricao = descricao;`n            DataAbertura = DateTime.Now;`n            Urgencia = urgencia;`n            Cliente = cliente;`n            Equipamento = equipamento;`n            `n            EstadoAtual = new GestaoManutencao.Core.States.EstadoAberta();`n            // Por enquanto, o estado será injetado ou controlado pelas classes de State`n            Prioridade = estrategiaPriorizacao.DeterminarPrioridade(this);`n        }`n`n        public void DefinirEstado(ISolicitacaoState novoEstado)`n        {`n            EstadoAtual = novoEstado ?? throw new ArgumentNullException(nameof(novoEstado));`n        }`n`n        public void AtribuirTecnico(Tecnico tecnico)`n        {`n            if (EstadoAtual == null)`n                throw new InvalidOperationException("Estado atual nao configurado.");`n            `n            EstadoAtual.AtribuirTecnico(this, tecnico);`n        }`n`n        public void ForcarAtribuicaoTecnico(Tecnico tecnico)`n        {`n            TecnicoResponsavel = tecnico;`n        }`n`n        public void AdicionarServico(ServicoRealizado servico)`n        {`n            if (EstadoAtual == null)`n                throw new InvalidOperationException("Estado atual nao configurado.");`n`n            EstadoAtual.AdicionarServico(this, servico);`n        }`n`n        public void ForcarAdicaoServico(ServicoRealizado servico)`n        {`n            _servicos.Add(servico ?? throw new ArgumentNullException(nameof(servico)));`n        }`n`n        public void AvancarEstado()`n        {`n            if (EstadoAtual == null)`n                throw new InvalidOperationException("Estado atual nao configurado.");`n`n            EstadoAtual.Avancar(this);`n        }`n`n        public void CancelarSolicitacao(string justificativa)`n        {`n            if (EstadoAtual == null)`n                throw new InvalidOperationException("Estado atual nao configurado.");`n`n            EstadoAtual.Cancelar(this, justificativa);`n        }`n`n        public decimal CalcularCustoTotal(ICalculoCustoStrategy estrategia)`n        {`n            if (estrategia == null)`n                throw new ArgumentNullException(nameof(estrategia));`n`n            return estrategia.Calcular(this);`n        }`n    }`n}
